module top_module (
    input clk,
    input reset,
    input up,
    output [2:0] count );reg [2:0] unused_count_reg;

    always @(posedge clk) begin
        if (reset)
            unused_count_reg <= 3'b000;
        else if (up)
            unused_count_reg <= unused_count_reg + 1;
        else
            unused_count_reg <= unused_count_reg - 1;
    end

    assign count = unused_count_reg;

endmodule
